import type { AnnotationsUnion } from '@/typings/serializers'
import type { Comment, FormField, State } from '../../models'
import type { IRecord } from './InstantProvider'

export function getRecordInState(
  state: State,
  record: IRecord,
): AnnotationsUnion | Comment | FormField | string | undefined {
  const existingAnnotations = state.get('annotations')
  const existingFormFields = state.get('formFields')
  const existingComments = state.get('comments')
  const existingFormFieldValues = state.get('formattedFormFieldValues')
  let formFieldName

  if (record.id.startsWith('form-field-value/')) {
    formFieldName = record.id.split('/')[1]
  }

  return (
    existingAnnotations.get(record.id) ||
    existingFormFields.find(value => value.id === record.id) ||
    existingComments.get(record.id) ||
    (formFieldName ? existingFormFieldValues.get(formFieldName) : undefined)
  )
}

export function isRecordInState(state: State, record: IRecord): boolean {
  return Boolean(getRecordInState(state, record))
}
